import{_ as e,c as s,o as d,a3 as t}from"./chunks/framework.CTM16EAR.js";const g=JSON.parse('{"title":"帮助文档部署与本地开发（当前口径）","description":"","frontmatter":{"search":false},"headers":[],"relativePath":"dev-log/SOP/docs-deployment.md","filePath":"dev-log/SOP/docs-deployment.md","lastUpdated":1775720707000}'),a={name:"dev-log/SOP/docs-deployment.md"};function i(c,o,n,l,r,p){return d(),s("div",null,o[0]||(o[0]=[t('<h1 id="帮助文档部署与本地开发-当前口径" tabindex="-1">帮助文档部署与本地开发（当前口径） <a class="header-anchor" href="#帮助文档部署与本地开发-当前口径" aria-label="Permalink to &quot;帮助文档部署与本地开发（当前口径）&quot;">​</a></h1><p><strong>Cloudflare / 外链帮助跳转</strong>（逐步操作）见同目录 <a href="./help-docs-cloudflare.html">help-docs-cloudflare.md</a>。</p><h2 id="_1-目的与范围" tabindex="-1">1. 目的与范围 <a class="header-anchor" href="#_1-目的与范围" aria-label="Permalink to &quot;1. 目的与范围&quot;">​</a></h2><p>说明三件事，避免和旧版「站内 HelpView + 外链」混淆：</p><ol><li><strong>应用内帮助</strong>：主应用里点「帮助」会<strong>整页跳转</strong>到打包进产物里的 <strong>VitePress 静态站</strong>，路径为 <strong><code>{BASE_URL}docs-app/</code></strong>（根部署多为 <code>/docs-app/</code>，子路径部署则为 <code>/{VITE_APP_BASE}/docs-app/</code>）。不再使用 <code>HelpView.vue</code>。</li><li><strong>桌面 / 完整前端构建</strong>：通过根目录 <strong><code>pnpm build:with-docs</code></strong> 把文档打进 <strong><code>public/.../docs-app</code></strong>，再随主站一起构建（Tauri 的 <code>beforeBuildCommand</code> 已配置为此命令）。</li><li><strong>独立文档站（GitHub Pages）</strong>：仍可用 <code>docs/</code> 下的 <strong><code>docs:deploy:github</code></strong> 发布到 Pages，与「应用内嵌文档」是<strong>两条可选链路</strong>，按需手动维护。</li></ol><h2 id="_2-概念对照" tabindex="-1">2. 概念对照 <a class="header-anchor" href="#_2-概念对照" aria-label="Permalink to &quot;2. 概念对照&quot;">​</a></h2><table tabindex="0"><thead><tr><th>名称</th><th>含义</th></tr></thead><tbody><tr><td><strong>docs-app</strong></td><td>应用内文档的 <strong>URL 路径段</strong> 与 <strong><code>public</code> 下目录名</strong>（见 <code>.gitignore</code> 中的 <code>public/docs-app</code> 等），不是单独的 npm 包名。</td></tr><tr><td><strong>VITEPRESS_BASE</strong></td><td>VitePress 的 <code>base</code>，嵌入应用时必须与主站 <code>import.meta.env.BASE_URL</code> + <code>docs-app/</code> 一致，由脚本注入。</td></tr><tr><td><strong>VITE_APP_BASE</strong></td><td>主站 Vite 的 <code>base</code>（子路径部署时用）。文档脚本会读取它来计算 <code>VITEPRESS_BASE</code>。</td></tr></tbody></table><h2 id="_3-根目录脚本-仓库根-package-json" tabindex="-1">3. 根目录脚本（仓库根 <code>package.json</code>） <a class="header-anchor" href="#_3-根目录脚本-仓库根-package-json" aria-label="Permalink to &quot;3. 根目录脚本（仓库根 `package.json`）&quot;">​</a></h2><p>常用命令：</p><table tabindex="0"><thead><tr><th>命令</th><th>作用</th></tr></thead><tbody><tr><td><code>pnpm dev</code></td><td>启动主站 Vite（默认 <strong>1420</strong>）。主站 <strong>listen 之后</strong> 会自动执行 <code>pnpm docs:dev:app</code>（VitePress，<strong>5173</strong>），除非下面例外。</td></tr><tr><td><code>pnpm dev:app</code></td><td>仅主站：<code>cross-env SKIP_DOCS_DEV=1 vite</code>，<strong>不</strong>自动起文档；点帮助会代理失败，适合只改主站、要更轻量时。</td></tr><tr><td><code>pnpm dev:with-docs</code></td><td>与 <code>pnpm dev</code> 相同（别名）。</td></tr><tr><td><code>pnpm docs:dev:app</code></td><td><code>node scripts/run-docs-for-app.mjs dev</code>：按 <code>VITE_APP_BASE</code> 设好 <code>VITEPRESS_BASE</code> 后，在 <code>docs/</code> 里跑 VitePress dev。</td></tr><tr><td><code>pnpm docs:build:for-app</code></td><td><code>run-docs-for-app.mjs build</code>：构建嵌入应用用的文档产物到 <code>docs/.vitepress/dist</code>。</td></tr><tr><td><code>pnpm build:with-docs</code></td><td><code>docs:build:for-app</code> → <code>node scripts/sync-docs-app.mjs</code>（拷贝到 <code>public/.../docs-app</code>）→ <code>pnpm build</code>。发布桌面端 / 需要自带帮助时应用此流程。</td></tr></tbody></table><p>辅助脚本说明：</p><ul><li><strong><code>scripts/run-docs-for-app.mjs</code></strong>：从环境变量或根目录 <code>.env*</code> 读取 <code>VITE_APP_BASE</code>，设置 <code>VITEPRESS_BASE</code> 为 <code>/{可选子路径}/docs-app/</code>，再在 <code>docs/</code> 执行 <code>docs:dev</code> 或 <code>docs:build:local</code>。</li><li><strong><code>scripts/sync-docs-app.mjs</code></strong>：把 <code>docs/.vitepress/dist</code> 同步到 <code>public/docs-app</code> 或 <code>public/{VITE_APP_BASE}/docs-app</code>，与上面 base 规则一致。</li></ul><p>开发时主站通过 <strong><code>vite.config.ts</code></strong> 把 <code>/{base}/docs-app</code> <strong>代理到 <code>http://127.0.0.1:5173</code></strong>（与 <code>docsDevPort</code> 一致）。若 <strong>5173 上已有进程</strong>（例如你已手动起了文档），则不会重复拉起 VitePress。</p><h2 id="_4-本地开发怎么预览" tabindex="-1">4. 本地开发怎么预览 <a class="header-anchor" href="#_4-本地开发怎么预览" aria-label="Permalink to &quot;4. 本地开发怎么预览&quot;">​</a></h2><h3 id="_4-1-与主应用一致-推荐-含-tauri-tauri-dev" tabindex="-1">4.1 与主应用一致（推荐，含 Tauri <code>tauri dev</code>） <a class="header-anchor" href="#_4-1-与主应用一致-推荐-含-tauri-tauri-dev" aria-label="Permalink to &quot;4.1 与主应用一致（推荐，含 Tauri `tauri dev`）&quot;">​</a></h3><p>在仓库根：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><ul><li>主应用：<code>http://localhost:1420</code>（或你配置的 host）。</li><li>应用内帮助：浏览器打开 <strong><code>http://localhost:1420/docs-app/</code></strong>（若配置了 <code>VITE_APP_BASE</code>，路径前加该前缀）。</li></ul><p>文档进程稍晚于主站启动属正常；若瞬间点帮助出现 5xx，可等终端里 VitePress 就绪后再试。</p><h3 id="_4-2-只起主站、不起文档" tabindex="-1">4.2 只起主站、不起文档 <a class="header-anchor" href="#_4-2-只起主站、不起文档" aria-label="Permalink to &quot;4.2 只起主站、不起文档&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev:app</span></span></code></pre></div><h3 id="_4-3-只在-docs-里改文档、独立预览-github-pages-默认-base" tabindex="-1">4.3 只在 <code>docs/</code> 里改文档、独立预览（GitHub Pages 默认 base） <a class="header-anchor" href="#_4-3-只在-docs-里改文档、独立预览-github-pages-默认-base" aria-label="Permalink to &quot;4.3 只在 `docs/` 里改文档、独立预览（GitHub Pages 默认 base）&quot;">​</a></h3><p><code>docs/.vitepress/config.mts</code> 在未设置 <code>VITEPRESS_BASE</code> 时默认 base 偏 <strong>GitHub Pages</strong>（如 <code>/pomotention/</code>），本地一般为：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:dev</span></span></code></pre></div><p>浏览器访问控制台输出的 Local 地址（含 base 前缀，例如 <code>http://localhost:5173/pomotention/</code>）。<strong>这与嵌入应用时的 <code>/docs-app/</code> 不是同一路径</strong>，改「应用内帮助」请以 <strong>4.1</strong> 为准验证。</p><h2 id="_5-独立文档站-发布到-github-pages" tabindex="-1">5. 独立文档站：发布到 GitHub Pages <a class="header-anchor" href="#_5-独立文档站-发布到-github-pages" aria-label="Permalink to &quot;5. 独立文档站：发布到 GitHub Pages&quot;">​</a></h2><p>文档项目脚本在 <strong><code>docs/package.json</code></strong>：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;scripts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;docs:deploy:github&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;vitepress build &amp;&amp; npx gh-pages -d .vitepress/dist&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>执行方式：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs:deploy:github</span></span></code></pre></div><p>成功后文档站地址取决于 <strong>gh-pages 分支与仓库设置</strong>（历史上常用：<a href="https://xeonilian.github.io/pomotention/" target="_blank" rel="noreferrer">https://xeonilian.github.io/pomotention/</a>）。<strong>应用内嵌文档不依赖此步骤</strong>；若只发桌面安装包，以 <strong><code>build:with-docs</code></strong> 为准。</p><h2 id="_6-为什么会出现「主站更新但帮助不更新」" tabindex="-1">6. 为什么会出现「主站更新但帮助不更新」 <a class="header-anchor" href="#_6-为什么会出现「主站更新但帮助不更新」" aria-label="Permalink to &quot;6. 为什么会出现「主站更新但帮助不更新」&quot;">​</a></h2><p>可能叠加多种情况：</p><ul><li><strong>Cloudflare 等只跑了 <code>pnpm build</code></strong>，未执行 <strong><code>build:with-docs</code></strong>，产物里没有新的 <code>public/.../docs-app</code>。</li><li><strong>GitHub Pages 文档</strong> 与 <strong>应用内嵌文档</strong> 是不同链路：前者要单独 <code>docs:deploy:github</code>，后者要跟主站构建绑在一起。</li></ul><h2 id="_7-日常操作-sop-简版" tabindex="-1">7. 日常操作 SOP（简版） <a class="header-anchor" href="#_7-日常操作-sop-简版" aria-label="Permalink to &quot;7. 日常操作 SOP（简版）&quot;">​</a></h2><h3 id="_7-1-改应用内帮助-与发布包一致" tabindex="-1">7.1 改应用内帮助（与发布包一致） <a class="header-anchor" href="#_7-1-改应用内帮助-与发布包一致" aria-label="Permalink to &quot;7.1 改应用内帮助（与发布包一致）&quot;">​</a></h3><ol><li>编辑 <code>docs/</code> 下 Markdown 或 <code>docs/.vitepress/config.mts</code>。</li><li>本地用 <strong><code>pnpm dev</code></strong> 在 <strong><code>/docs-app/</code></strong> 下自测。</li><li>发版前在仓库根执行 <strong><code>pnpm build:with-docs</code></strong>（或与 CI 中 Tauri / 前端构建命令对齐）。</li></ol><h3 id="_7-2-只更新-github-pages-公开文档站" tabindex="-1">7.2 只更新 GitHub Pages 公开文档站 <a class="header-anchor" href="#_7-2-只更新-github-pages-公开文档站" aria-label="Permalink to &quot;7.2 只更新 GitHub Pages 公开文档站&quot;">​</a></h3><ol><li>在 <code>docs/</code> 修改并 <strong><code>pnpm docs:dev</code></strong> 按 Pages base 自测。</li><li><strong><code>pnpm docs:deploy:github</code></strong>。</li><li>打开 Pages URL 强制刷新验证。</li></ol><h3 id="_7-3-发布后验证-应用内" tabindex="-1">7.3 发布后验证（应用内） <a class="header-anchor" href="#_7-3-发布后验证-应用内" aria-label="Permalink to &quot;7.3 发布后验证（应用内）&quot;">​</a></h3><ol><li>用 <strong><code>build:with-docs</code></strong> 产物或安装包打开应用。</li><li>点「帮助」，确认进入 <strong><code>docs-app</code></strong> 且内容为新版本。</li></ol><h2 id="_8-故障排查" tabindex="-1">8. 故障排查 <a class="header-anchor" href="#_8-故障排查" aria-label="Permalink to &quot;8. 故障排查&quot;">​</a></h2><h3 id="_8-1-开发时-docs-app-5xx-或打不开" tabindex="-1">8.1 开发时 <code>/docs-app/</code> 5xx 或打不开 <a class="header-anchor" href="#_8-1-开发时-docs-app-5xx-或打不开" aria-label="Permalink to &quot;8.1 开发时 `/docs-app/` 5xx 或打不开&quot;">​</a></h3><ul><li>是否用的 <strong><code>pnpm dev</code></strong>（而非仅 <strong><code>pnpm dev:app</code></strong>）？</li><li>终端里 VitePress 是否已启动；<strong>5173</strong> 是否被其它程序占用导致异常。</li><li>子路径部署时 <strong><code>VITE_APP_BASE</code></strong> 是否与 <strong><code>run-docs-for-app</code> / <code>sync-docs-app</code></strong> 所用一致。</li></ul><h3 id="_8-2-sync-docs-app-报错缺少-dist" tabindex="-1">8.2 <code>sync-docs-app</code> 报错缺少 dist <a class="header-anchor" href="#_8-2-sync-docs-app-报错缺少-dist" aria-label="Permalink to &quot;8.2 `sync-docs-app` 报错缺少 dist&quot;">​</a></h3><p>先执行 <strong><code>pnpm docs:build:for-app</code></strong>，再执行 <strong><code>node scripts/sync-docs-app.mjs</code></strong>（或直接 <strong><code>pnpm build:with-docs</code></strong>）。</p><h3 id="_8-3-docs-deploy-github-失败" tabindex="-1">8.3 <code>docs:deploy:github</code> 失败 <a class="header-anchor" href="#_8-3-docs-deploy-github-失败" aria-label="Permalink to &quot;8.3 `docs:deploy:github` 失败&quot;">​</a></h3><ul><li>检查 Node / pnpm、网络、GitHub 权限。</li><li>在 <code>docs/</code> 重新 <strong><code>pnpm install</code></strong> 后重试。</li></ul><h3 id="_8-4-命令成功但线上文档没变化" tabindex="-1">8.4 命令成功但线上文档没变化 <a class="header-anchor" href="#_8-4-命令成功但线上文档没变化" aria-label="Permalink to &quot;8.4 命令成功但线上文档没变化&quot;">​</a></h3><ul><li>等待 CDN / Pages 刷新，强制刷新浏览器。</li><li>确认你看的是 <strong>Pages 站</strong> 还是 <strong>应用内 docs-app</strong>，不要混用判断标准。</li></ul><h2 id="_9-当前不默认承诺的自动化" tabindex="-1">9. 当前不默认承诺的自动化 <a class="header-anchor" href="#_9-当前不默认承诺的自动化" aria-label="Permalink to &quot;9. 当前不默认承诺的自动化&quot;">​</a></h2><p>以下内容需平台或仓库内配置确认写入并跑通后，才可升格为「默认事实」：</p><ul><li>PR 合并后 GitHub Actions 自动部署 docs 到 Pages。</li><li>Cloudflare 单流水线同时发布主站与独立文档路径。</li><li>主站与 GitHub Pages 文档始终同一时刻更新。</li></ul><h2 id="_10-后续收敛目标-to-be" tabindex="-1">10. 后续收敛目标（To-Be） <a class="header-anchor" href="#_10-后续收敛目标-to-be" aria-label="Permalink to &quot;10. 后续收敛目标（To-Be）&quot;">​</a></h2><ul><li>对外入口与发布策略尽量统一（例如统一到 Cloudflare）。</li><li>明确「公开文档站」与「应用内嵌文档」是否继续双轨；若合并，需同步构建命令与入口 URL。</li></ul><h2 id="_11-相关文件" tabindex="-1">11. 相关文件 <a class="header-anchor" href="#_11-相关文件" aria-label="Permalink to &quot;11. 相关文件&quot;">​</a></h2><ul><li><strong><code>docs/dev-log/SOP/help-docs-cloudflare.md</code></strong>：帮助跳转与 Cloudflare（<code>VITE_HELP_DOCS_URL</code> 等）SOP。</li><li>根目录 <strong><code>package.json</code></strong>：<code>dev</code>、<code>dev:app</code>、<code>build:with-docs</code>、<code>docs:*</code> 脚本。</li><li><strong><code>scripts/run-docs-for-app.mjs</code></strong>、<strong><code>scripts/sync-docs-app.mjs</code></strong>：嵌入应用的 base 与同步。</li><li><strong><code>vite.config.ts</code></strong>：<code>docs-app</code> 代理、子路径下误访问 <code>/docs-app</code> 的跳转、文档 dev 子进程逻辑。</li><li><strong><code>docs/.vitepress/config.mts</code></strong>：VitePress 站点配置（<code>base</code> 常由 <code>VITEPRESS_BASE</code> 覆盖）。</li><li><strong><code>docs/package.json</code></strong>：含 <strong><code>docs:deploy:github</code></strong>。</li><li><strong><code>src/composables/useDocsUrl.ts</code></strong>：<code>getDocsStaticPath</code>、<code>navigateToBuiltDocs</code>。</li><li><strong><code>src/router/index.ts</code></strong>、<code>src/views/MainLayout.vue</code>：<code>/help</code> 与菜单「帮助」行为。</li><li><strong><code>src/views/SettingView.vue</code></strong>：若存在对 GitHub Pages 文档站的连通性检测等，常量如 <code>NET_DOCS</code> 需与真实 Pages 地址一致。</li><li><strong><code>src-tauri/tauri.conf.json</code></strong>：<code>beforeDevCommand</code>（<code>pnpm dev</code>）、<code>beforeBuildCommand</code>（<code>pnpm build:with-docs</code>）。</li><li><strong><code>.gitignore</code></strong>：<code>public/docs-app</code>、<code>public/**/docs-app</code>（构建生成，一般不入库）。</li><li><strong><code>docs/dev-log/SOP/release.md</code></strong>：桌面端发布流程（若存在）。</li></ul>',57)]))}const u=e(a,[["render",i]]);export{g as __pageData,u as default};
